sql:
SELECT COUNT(suicides_no) AS suicide_count
FROM suicide_data
WHERE data_id IN (0, 1);

SELECT MAX(suicides_no) AS max_suicides
FROM suicide_data
WHERE sex = 'male' AND age_group = '15-24 years';
